import { useLang } from '../lib/LangContext.jsx'

// The official QPC employee card template image — the design is already complete.
// We only overlay the actual employee data values on top.
const CARD_TEMPLATE = "data:image/jpeg;base64,"

const DESIGNATION_AR = {
  'Coach':'مدرب','Assistant Coach':'مدرب مساعد','Technical Expert':'خبير تقني',
  'Physiotherapist':'معالج فيزيائي','Doctor':'طبيب','Secretary General':'الأمين العام',
  'Executive Manager':'مدير تنفيذي','Administration Secretary':'سكرتير إداري',
  'Secretary Assistant':'مساعد سكرتير','Administrative National Team':'إداري الفريق الوطني',
  'Administrative Youth Team':'إداري فريق الشباب',
  'Administrative Center & Development':'إداري المركز والتطوير',
  'Accountant':'محاسب','Public Relation Officer':'مسؤول علاقات عامة',
  'Receptionist':'موظف استقبال','Board Member':'عضو مجلس إدارة',
  'Official':'مسؤول','Delegate':'مندوب','Employee':'موظف',
  'Store Keeper':'أمين مخزن','Waiter':'نادل','Worker':'عامل','Driver':'سائق',
}

export function generateEmployeeCard(emp) {
  const desigAr  = emp.designation_ar || DESIGNATION_AR[emp.designation] || emp.designation || ''
  const staffId  = emp.employee_number ? ('QPC-' + emp.employee_number) : '—'
  const jobId    = emp.job_id || '—'
  const qssNum   = emp.qss_number ? ('QSS-' + emp.qss_number) : '—'
  const phone    = emp.phone || '+974 44040200'
  const email    = emp.email || 'name@email.com'
  const photo    = emp.photo_url || ''

  // The card template is 900×600px. All text positions are calibrated to that size.
  // We only draw the employee-specific data — everything else (logos, icons, labels,
  // background design) is already in the template image and never touched.
  const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<title>ID Card – ${emp.name || ''}</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=Tajawal:wght@400;500;700&display=swap');
*{box-sizing:border-box;margin:0;padding:0}
body{
  background:#888;
  font-family:Inter,Arial,sans-serif;
  display:flex;flex-direction:column;
  align-items:center;justify-content:center;
  min-height:100vh;padding:32px 20px;gap:20px;
}
.no-print{display:flex;gap:10px}
.btn{padding:9px 22px;border:none;border-radius:8px;cursor:pointer;font-family:inherit;font-size:13px;font-weight:600}
@media print{
  body{background:white;padding:0;justify-content:flex-start}
  .no-print{display:none!important}
  @page{size:900px 600px;margin:0}
}

/* ── CARD WRAPPER ── */
.card{
  width:900px;height:600px;
  position:relative;
  border-radius:22px;
  overflow:hidden;
  box-shadow:0 16px 64px rgba(0,0,0,.45);
}
/* Template image fills the entire card exactly */
.card-bg{
  position:absolute;inset:0;
  width:100%;height:100%;
  object-fit:cover;
  display:block;
  border-radius:22px;
}

/* ── PHOTO OVERLAY ── */
/* Sits inside the gold ring on the template at approx center (145,287) r=107 */
.photo-circle{
  position:absolute;
  left:38px; top:178px;
  width:214px; height:214px;
  border-radius:50%;
  overflow:hidden;
  z-index:10;
  background:transparent;
}
.photo-circle img{
  width:100%;height:100%;
  object-fit:cover;object-position:top center;
}
/* placeholder silhouette when no photo */
.photo-placeholder{
  width:100%;height:100%;
  display:flex;align-items:center;justify-content:center;
}

/* ── TEXT OVERLAYS ── */

/* Full Name (EN) — large dark navy bold */
.text-name-en{
  position:absolute;
  left:312px; top:178px;
  font-family:Inter,Arial,sans-serif;
  font-size:46px; font-weight:800;
  color:#1a2340;
  letter-spacing:-0.02em;
  line-height:1;
  z-index:10;
  white-space:nowrap;
}
/* Arabic Name */
.text-name-ar{
  position:absolute;
  left:312px; top:244px;
  right:24px;
  font-family:Tajawal,Arial,sans-serif;
  font-size:28px; font-weight:600;
  color:#1a2340;
  direction:rtl;text-align:right;
  z-index:10;
  white-space:nowrap;
}
/* Position EN */
.text-pos-en{
  position:absolute;
  left:312px; top:338px;
  font-family:Inter,Arial,sans-serif;
  font-size:22px; font-weight:700;
  color:#1a2340;
  z-index:10;
}
/* Position AR (crimson) */
.text-pos-ar{
  position:absolute;
  left:312px; top:376px;
  right:24px;
  font-family:Tajawal,Arial,sans-serif;
  font-size:19px; font-weight:700;
  color:#7a1325;
  direction:rtl;text-align:right;
  z-index:10;
}

/* Staff ID value */
.text-staff-id{
  position:absolute;
  left:160px; top:452px;
  font-family:Inter,Arial,sans-serif;
  font-size:16px; font-weight:700;
  color:#1a1a1a;
  z-index:10;
}
/* Job ID value */
.text-job-id{
  position:absolute;
  left:445px; top:452px;
  font-family:Inter,Arial,sans-serif;
  font-size:16px; font-weight:700;
  color:#1a1a1a;
  z-index:10;
}
/* QSS Number value */
.text-qss{
  position:absolute;
  left:725px; top:452px;
  font-family:Inter,Arial,sans-serif;
  font-size:16px; font-weight:700;
  color:#1a1a1a;
  z-index:10;
}

/* Phone value */
.text-phone{
  position:absolute;
  left:192px; top:548px;
  font-family:Inter,Arial,sans-serif;
  font-size:18px; font-weight:500;
  color:#ffffff;
  z-index:10;
  letter-spacing:0.01em;
}
/* Email value */
.text-email{
  position:absolute;
  left:562px; top:548px;
  font-family:Inter,Arial,sans-serif;
  font-size:18px; font-weight:500;
  color:#ffffff;
  z-index:10;
}
</style>
</head>
<body>

<div class="no-print">
  <button class="btn" onclick="window.print()" style="background:#7a1325;color:white">🖨 Print / Save PDF</button>
  <button class="btn" onclick="if(window.opener||window.history.length<=1){window.close()}else{history.back()}" style="background:white;color:#555;border:1px solid #ddd">← Back</button>
</div>

<div class="card">

  <!-- Template image — the full card design -->
  <img class="card-bg" src="${CARD_TEMPLATE}" alt="QPC ID Card"/>

  <!-- Photo -->
  <div class="photo-circle">
    ${photo
      ? `<img src="${photo}" alt="${emp.name || ''}"/>`
      : `<div class="photo-placeholder">
           <svg viewBox="0 0 100 115" width="86%" style="margin-top:10%">
             <circle cx="50" cy="34" r="26" fill="#b0b8c1"/>
             <ellipse cx="50" cy="98" rx="40" ry="28" fill="#b0b8c1"/>
           </svg>
         </div>`
    }
  </div>

  <!-- Full Name (EN) -->
  <div class="text-name-en">${emp.name || 'Full Name'}</div>

  <!-- Arabic Name -->
  <div class="text-name-ar">${emp.name_ar || 'الاسم الكامل'}</div>

  <!-- Position EN -->
  <div class="text-pos-en">${emp.designation || 'Position Name'}</div>

  <!-- Position AR -->
  <div class="text-pos-ar">${desigAr || 'المسمى الوظيفي'}</div>

  <!-- ID values — overlay on top of the template labels+icons that are already in the image -->
  <div class="text-staff-id">${staffId}</div>
  <div class="text-job-id">${jobId}</div>
  <div class="text-qss">${qssNum}</div>

  <!-- Contact values — overlay on top of the template icons in the crimson footer -->
  <div class="text-phone">${phone}</div>
  <div class="text-email">${email}</div>

</div>
</body>
</html>`

  return html
}

export default function EmployeeCardButton({ emp }) {
  const { lang } = useLang()
  const ar = lang === 'ar'

  function handleGenerate() {
    const html = generateEmployeeCard(emp)
    const win = window.open('', '_blank')
    win.document.write(html)
    win.document.close()
  }

  return (
    <button
      onClick={handleGenerate}
      className="action-btn"
      style={{
        borderColor: '#7a1325',
        color: '#7a1325',
        padding: '5px 12px',
        display: 'flex',
        alignItems: 'center',
        gap: 6,
      }}
      onMouseEnter={e => { e.currentTarget.style.background = '#f9e5ea' }}
      onMouseLeave={e => { e.currentTarget.style.background = '' }}
    >
      <i className="ti ti-id-badge" style={{ fontSize: 14 }} />
      <span>{ar ? 'بطاقة الموظف' : 'ID Card'}</span>
    </button>
  )
}
